const fs = require('fs');
const path = require('path');

const playersFilePath = path.join(__dirname, '../data/players.json');

// Load existing players
let existingPlayers = [];
if (fs.existsSync(playersFilePath)) {
  try {
    existingPlayers = JSON.parse(fs.readFileSync(playersFilePath, 'utf8'));
  } catch (e) {
    console.error("Failed reading base JSON", e);
  }
}

// Add proper missing fields to existing players based on name mappings
const knownTitles = {
  "Rohit Sharma": 6, "MS Dhoni": 5, "Ambati Rayudu": 6, "Hardik Pandya": 5, "Kieron Pollard": 5,
  "Jasprit Bumrah": 5, "Suresh Raina": 4, "Ravindra Jadeja": 4, "Lasith Malinga": 4, "Sunil Narine": 3,
  "Andre Russell": 2, "Gautam Gambhir": 2, "Yuvraj Singh": 2, "Shane Watson": 2, "Dwayne Bravo": 3,
  "Ravichandran Ashwin": 2, "Faf du Plessis": 2, "Ruturaj Gaikwad": 1, "Shubman Gill": 1, "Rashid Khan": 1,
  "Axar Patel": 0, "Virat Kohli": 0, "AB de Villiers": 0, "Chris Gayle": 0, "KL Rahul": 0
};

const knownDebut = {
  "Virat Kohli": 2008, "MS Dhoni": 2008, "Rohit Sharma": 2008, "Suresh Raina": 2008, "Gautam Gambhir": 2008,
  "Dinesh Karthik": 2008, "Shikhar Dhawan": 2008, "Robin Uthappa": 2008, "AB de Villiers": 2008, "Chris Gayle": 2009,
  "Kieron Pollard": 2010, "Ravindra Jadeja": 2008, "Sunil Narine": 2012, "Andre Russell": 2012, "Lasith Malinga": 2009,
  "Jasprit Bumrah": 2013, "Hardik Pandya": 2015, "Rashid Khan": 2017, "Shubman Gill": 2018, "Ruturaj Gaikwad": 2020,
  "Yashasvi Jaiswal": 2020, "Rinku Singh": 2018, "Tilak Varma": 2022, "Heinrich Klaasen": 2018, "Pat Cummins": 2014
};

existingPlayers = existingPlayers.map(p => {
  const active = p.active !== undefined ? p.active : true;
  const retired = p.retired !== undefined ? p.retired : !active;
  const titles = knownTitles[p.name] !== undefined ? knownTitles[p.name] : (p.teams && (p.teams.includes("CSK") || p.teams.includes("MI")) ? 1 : 0);
  const debut = knownDebut[p.name] !== undefined ? knownDebut[p.name] : (retired ? 2008 : 2016);

  return {
    ...p,
    retired,
    iplTitles: titles,
    debutYear: debut,
    active: active // Keep synced
  };
});

