// Map standard enrichment defaults to all extra items
const expandedPlayers = extraPlayers.map(p => ({
  ...p,
  imageUrl: p.imageUrl || "https://images.unsplash.com/photo-1531415074968-036ba1b575da?q=80&w=2067&auto=format&fit=crop",
  careerRuns: p.careerRuns || (p.role === "Bowler" ? "150" : "1,800"),
  playingStyle: p.playingStyle || (p.role === "Batsman" ? "Stroke Maker" : p.role === "Bowler" ? "Pace Attacker" : "Clutch Operator"),
  keyStrength: p.keyStrength || "Match Presence",
  eraGeneration: p.retired ? "Historical Greats" : "Modern Dynamic",
  signatureMetric: p.signatureMetric || (p.iplTitles > 0 ? `${p.iplTitles}-Time Champion` : "Impact Performer")
}));

// Concatenate and deduplicate by name
const finalMap = new Map();
existingPlayers.forEach(p => finalMap.set(p.name, p));
expandedPlayers.forEach(p => finalMap.set(p.name, p));

const uniqueFinalList = Array.from(finalMap.values());

console.log("Writing expanded JSON: ", uniqueFinalList.length, " unique players generated.");

fs.writeFileSync(playersFilePath, JSON.stringify(uniqueFinalList, null, 2));
